css:
.loader {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
   width: 28px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: var(--loader-color, #0ea5e9);
   animation: l7 2s infinite;
}
@keyframes l7  {
  0%, 100% {transform:translate(-30px,-30px);
  box-shadow: 0 0 var(--loader-secondary-color, #67e8f9), 0 0 var(--loader-secondary-color, #67e8f9)}
12.5% {transform:translate( 30px,-30px);
  box-shadow: -15px 0 var(--loader-secondary-color, #67e8f9),-30px 0 var(--loader-secondary-color, #67e8f9)}
25% {transform:translate( 30px,-30px);
  box-shadow: 0 0 var(--loader-secondary-color, #67e8f9), 0 0 var(--loader-secondary-color, #67e8f9)}
37.5% {transform:translate( 30px, 30px);
  box-shadow: 0 -15px var(--loader-secondary-color, #67e8f9), 0 -30px var(--loader-secondary-color, #67e8f9)}
50% {transform:translate( 30px, 30px);
  box-shadow: 0 0 var(--loader-secondary-color, #67e8f9), 0 0 var(--loader-secondary-color, #67e8f9)}
62.5% {transform:translate(-30px, 30px);
  box-shadow: 15px 0 var(--loader-secondary-color, #67e8f9), 30px 0 var(--loader-secondary-color, #67e8f9)}
75% {transform:translate(-30px, 30px);
  box-shadow: 0 0 var(--loader-secondary-color, #67e8f9), 0 0 var(--loader-secondary-color, #67e8f9)}
87.5% {transform:translate(-30px,-30px);
  box-shadow: 0 15px var(--loader-secondary-color, #67e8f9), 0 30px var(--loader-secondary-color, #67e8f9)}
}
